import java.util.*

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    var maxTime = 0L
    if (edges.isNotEmpty()) {
        maxTime = edges.maxOf { it[2] }
    }

    var low = 0L
    var high = maxTime

    while (low < high) {
        val mid = (low + high) / 2
        val comps = countComponents(n.toInt(), edges, mid)
        if (comps >= k) {
            high = mid
        } else {
            low = mid + 1
        }
    }
    return low
}

private fun countComponents(n: Int, edges: Array<Array<Long>>, t: Long): Long {
    val graph = Array(n) { mutableListOf<Int>() }
    for (edge in edges) {
        val time = edge[2]
        if (time > t) {
            val u = edge[0].toInt()
            val v = edge[1].toInt()
            graph[u].add(v)
            graph[v].add(u)
        }
    }

    val visited = BooleanArray(n) { false }
    var count = 0
    val queue = LinkedList<Int>()
    for (i in 0 until n) {
        if (!visited[i]) {
            count++
            queue.add(i)
            visited[i] = true
            while (queue.isNotEmpty()) {
                val node = queue.poll()
                for (neighbor in graph[node]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true
                        queue.add(neighbor)
                    }
                }
            }
        }
    }
    return count.toLong()
}
